def _parse_size(value):
    try:
        if isinstance(value, (int, float)):
            value_type = "px"
            value = float(value)
            assert value > 0
        else:
            value_type = "%"
            value = float(value.strip("%"))
            assert 0 <= value <= 100
    except Exception:
        msg = "Cannot parse value {!r} as {!r}".format
        raise ValueError(msg(value, value_type))
    return value, value_type

